def reverse_string(s: String) -> String:
    var result = String("")
    var n = s.byte_length()
    for i in range(n):
        result += String(s[byte=n - 1 - i])
    return result

def count_vowels(s: String) -> Int:
    var count = 0
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            c += 32
        if c == 97 or c == 101 or c == 105 or c == 111 or c == 117:
            count += 1
    return count

def caesar_shift(s: String, shift: Int) -> String:
    var result = String("")
    for cp in s.codepoints():
        var c = Int(cp)
        if c >= 65 and c <= 90:
            c = (c - 65 + shift) % 26 + 65
        elif c >= 97 and c <= 122:
            c = (c - 97 + shift) % 26 + 97
        result += chr(c)
    return result

