struct MinMax { double min; double max; };
MinMax minmax(const double* xs, int n){
    double lo = xs[0];
    double hi = xs[0];
    for(int i = 1; i < n; ++i){
        if(xs[i] < lo) lo = xs[i];
        if(xs[i] > hi) hi = xs[i];
    }
    return MinMax{lo, hi};
}

